import React, { useEffect, useState } from 'react';
import { getTasks, updateTask, deleteTask } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { format, isPast } from 'date-fns';

const STATUS_OPTIONS = ['todo','in-progress','review','completed'];

export default function Tasks() {
  const { isAdmin } = useAuth();
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');

  useEffect(() => {
    getTasks()
      .then(res => setTasks(res.data.tasks))
      .catch(()=>toast.error('Failed'))
      .finally(()=>setLoading(false));
  }, []);

  const handleStatusChange = async (id, status) => {
    try {
      const res = await updateTask(id,{status});
      setTasks(tasks.map(t=>t._id===id?res.data.task:t));
      toast.success('Updated');
    } catch { toast.error('Failed'); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete task?')) return;
    try {
      await deleteTask(id);
      setTasks(tasks.filter(t=>t._id!==id));
      toast.success('Deleted');
    } catch { toast.error('Failed'); }
  };

  const filtered = tasks.filter(t=>{
    const matchStatus = filter==='all' ? true : t.status===filter;
    const matchSearch = search ? 
      t.title.toLowerCase().includes(search.toLowerCase()) ||
      t.assignedTo?.name?.toLowerCase().includes(search.toLowerCase())
      : true;
    return matchStatus && matchSearch;
  });

  if (loading) return <div style={{textAlign:'center',padding:'60px',color:'#fff'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',padding:'30px',background:'linear-gradient(135deg,#0f172a,#022c22)'}}>

      {/* HEADER */}
      <div style={{display:'flex',justifyContent:'space-between',marginBottom:'20px',flexWrap:'wrap',gap:'10px'}}>
        <h1 style={{fontSize:'30px',color:'#4ade80'}}>All Tasks</h1>

        <input
          placeholder="Search..."
          value={search}
          onChange={e=>setSearch(e.target.value)}
          style={{
            padding:'8px 12px',
            borderRadius:'8px',
            border:'1px solid rgba(255,255,255,0.2)',
            background:'rgba(255,255,255,0.1)',
            color:'#fff'
          }}
        />
      </div>

      {/* FILTER */}
      <div style={{display:'flex',gap:'8px',marginBottom:'20px',flexWrap:'wrap'}}>
        {['all',...STATUS_OPTIONS].map(s=>(
          <button key={s}
            onClick={()=>setFilter(s)}
            style={{
              padding:'7px 12px',
              borderRadius:'8px',
              border:'none',
              cursor:'pointer',
              background:filter===s?'#22c55e':'rgba(255,255,255,0.1)',
              color:filter===s?'#022c22':'#bbf7d0',
              fontSize:'13px'
            }}>
            {s}
          </button>
        ))}
      </div>

      {/* TABLE */}
      <div style={{background:'rgba(255,255,255,0.06)',padding:'15px',borderRadius:'12px',border:'1px solid rgba(255,255,255,0.1)'}}>

        {filtered.length===0 ? (
          <p style={{textAlign:'center',color:'#9ca3af'}}>No tasks found</p>
        ) : (
          <div style={{display:'flex',flexDirection:'column',gap:'10px'}}>

            {filtered.map(task=>{
              const overdue = task.deadline && isPast(new Date(task.deadline)) && task.status!=='completed';

              return (
                <div key={task._id}
                  style={{
                    padding:'14px',
                    borderRadius:'10px',
                    background:'rgba(0,0,0,0.2)',
                    display:'flex',
                    justifyContent:'space-between',
                    flexWrap:'wrap',
                    gap:'10px'
                  }}>

                  {/* LEFT */}
                  <div>
                    <div style={{fontSize:'15px',fontWeight:'600',color:'#fff'}}>
                      {task.title}
                    </div>

                    <div style={{fontSize:'12px',color:'#9ca3af'}}>
                      {task.project?.name}
                    </div>

                    <div style={{fontSize:'12px',color:'#bbf7d0'}}>
                      {task.assignedTo?.name || 'Unassigned'}
                    </div>
                  </div>

                  {/* RIGHT */}
                  <div style={{textAlign:'right'}}>

                    <div style={{fontSize:'12px',color:'#e5e7eb'}}>
                      {task.status}
                    </div>

                    {task.deadline && (
                      <div style={{fontSize:'12px',color:overdue?'#f87171':'#9ca3af'}}>
                        {format(new Date(task.deadline),'MMM dd')}
                      </div>
                    )}

                    {isAdmin && (
                      <div style={{marginTop:'6px',display:'flex',gap:'6px',justifyContent:'flex-end'}}>
                        <select
                          value={task.status}
                          onChange={e=>handleStatusChange(task._id,e.target.value)}
                          style={{fontSize:'12px',padding:'4px'}}
                        >
                          {STATUS_OPTIONS.map(s=><option key={s}>{s}</option>)}
                        </select>

                        <button onClick={()=>handleDelete(task._id)}
                          style={{background:'none',border:'none',color:'#f87171',cursor:'pointer'}}>
                          🗑
                        </button>
                      </div>
                    )}

                  </div>

                </div>
              );
            })}

          </div>
        )}

      </div>

    </div>
  );
}
